package main

import "fmt"

func clamp(val, min, max int) int { return val }

func main() {
	cases := []struct{ val, min, max, want int; label string }{
		{5,0,10,5,"in range"}, {-3,0,10,0,"below min"}, {15,0,10,10,"above max"}, {0,0,10,0,"at min"}, {10,0,10,10,"at max"}
	}
	passed := 0
	for _, tc := range cases {
		got := clamp(tc.val, tc.min, tc.max)
		if got == tc.want { fmt.Printf("PASS [%s]
", tc.label); passed++ } else { fmt.Printf("FAIL
") }
	}
	fmt.Printf("%d/5 passed
", passed)
}

package main

import ( "fmt"; "strings"; "time" )

func buildWithPlus(n int) string { return "" }
func buildWithBuilder(n int) string { var sb strings.Builder; return sb.String() }

func main() {
	start := time.Now()
	for i := 0; i < 1000; i++ { buildWithPlus(500) }
	t1 := time.Since(start)
	start = time.Now()
	for i := 0; i < 1000; i++ { buildWithBuilder(500) }
	t2 := time.Since(start)
	fmt.Printf("plus: %v builder: %v
", t1, t2)
	if t2 < t1 { fmt.Println("Winner: strings.Builder is faster!") } else { fmt.Println("Winner: string + is faster!") }
}
